import React, { useState } from "react";
import wormImg from "../assets/images/meetEducation/wormImg.png";
import Worm from "../components/Worm";

const APPLE_GRAPHIC = "data:image/png;base64,";

const APPLE_CONTENT = [
  {
    title: "תקומה",
    text: 'מש"ק תקומה ישרת בסביבה אזרחית במטרה לתמוך בילדים ובני נוער מאוכלוסיות שנפגעו במלחמת חרבות ברזל. התפקיד כולל שילוב בבתי ספר ובמרכזים חינוכיים. שם הם מעבירים פעילויות חינוכיות, חברתיות ורגשיות.',
    id: "tkuma",
  },
  {
    title: "גשרים",
    text: 'התפקיד הוקם בשיתוף פעולה עם 8200. מש"ק גשרים עובד עם אוכלוסיה אזרחית בפריפריה במטרה לתת הזדמנות שווה לתלמידים בפריפריה חברתית בתחומי הסייבר והתכנות.',
    id: "gsharim",
  },
  {
    title: 'הו"ד',
    text: 'מש"קיות הוראה והדרכה של חיילים מאוכלוסיות ייחודיות, מטרת התפקיד היא שילוב אוכלוסיות מיוחדות באופן מיטבי בצה"ל ומניעת נשר.',
    text2: "רוצים לדעת על המגמות השונות?",
    textWorm: "לחצו על הכפתור!",
    id: "hod",
  },
  {
    title: 'גדנ"ע',
    text: 'מפקדי נוער בגדנ"ע יפקדו על מלש"בים למטרת העלאת המוטיבציה בקרב בני נוער לשירות קרבי ולחיזוק עמדות חיוביות לקראת שירותם.',
    id: "gadna",
  },
  {
    title: "חונכות",
    text: 'תומכות בשילוב חיילים עם אוטיזם בצה"ל.',
    id: "honhot",
  },
];

function Apple({ onBack, openedApple, hodCompleted, setHodCompleted }) {
  const [showPopup, setShowPopup] = useState(false);

  const wormDone = hodCompleted;
  const setWormDone = setHodCompleted;

  const currentApple = APPLE_CONTENT.find(
    (item) => item.id === openedApple
  );

  const isHod = currentApple?.id === "hod";
  const isBackLocked = isHod && !wormDone;

  const handleBack = () => {
    if (isBackLocked) return;
    onBack();
  };

  const handleBackKeyDown = (event) => {
    if (event.key === "Enter" || event.key === " ") {
      event.preventDefault();
      handleBack();
    }
  };

  if (!currentApple) {
    return null;
  }

  const isIPhone =
  typeof navigator !== "undefined" &&
  /iPhone|iPod/i.test(navigator.userAgent);

  return (
    <div>
      <div className="apple-container">
        <svg
          width="300"
          height="451"
          viewBox="0 0 340 451"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          className="apple-content-svg"
          role="img"
          aria-label={`מידע על ${currentApple.title}`}
          style={{
            transform: "translate(-1rem, -3rem)",
          }}
        >
          <image
            href={APPLE_GRAPHIC}
            x="-15"
            y="0"
            width="420"
            height="491"
            preserveAspectRatio="xMidYMid meet"
          />

          {/* אזור חזרה לעץ על העלה */}
          <g
            role="button"
            tabIndex={isBackLocked ? -1 : 0}
            aria-label="חזרה לעץ"
            aria-disabled={isBackLocked}
            onClick={handleBack}
            onKeyDown={handleBackKeyDown}
            style={{
              cursor: isBackLocked ? "not-allowed" : "pointer",
              opacity: isBackLocked ? 0.45 : 1,
              outline: "none",
            }}
          >
            <path
              d="M188 79C200 25 249 -4 332 2C325 48 294 94 220 111C203 108 192 98 188 79Z"
              fill="#000000"
              fillOpacity="0.001"
            />

            <foreignObject
              x="200"
              y="60"
              width="102"
              height="58"
              pointerEvents="none"
            >
              <div
                xmlns="http://www.w3.org/1999/xhtml"
                style={{
                  color: "white",
                  fontSize: "17px",
                  fontFamily: "rubik-bold",
                  fontWeight: 700,
                  textAlign: "center",
                  direction: "rtl",
                  lineHeight: 1.08,
                  textShadow: "0 1px 3px rgba(0, 70, 20, 0.8)",
                  pointerEvents: "none",
                }}
              >
                חזרה
                <br />
                לעץ
              </div>
            </foreignObject>
          </g>

          {/* כותרת */}
          <text
            x="185"
            y="200"
            textAnchor="middle"
            dominantBaseline="middle"
            fontSize="27"
            fontFamily="rubik-bold"
            fontWeight="700"
            fill="white"
            style={{
              filter: "drop-shadow(0 2px 2px rgba(80, 0, 0, 0.45))",
            }}
          >
            {currentApple.title}
          </text>

          {/* תוכן התפוח */}
          <foreignObject x="65" y="215" width="240" height={isHod ? 122 : 174}>
            <div
              xmlns="http://www.w3.org/1999/xhtml"
              style={{
                width: "100%",
                height: "100%",
                display: "flex",
                alignItems: "flex-start",
                justifyContent: "center",
                color: "white",
                fontSize: isHod ? "16.5px" : "17px",
                fontFamily: "rubik",
                textAlign: "center",
                direction: "rtl",
                lineHeight: 1.45,
                textShadow: "0 1px 3px rgba(80, 0, 0, 0.5)",
                overflow: "hidden",
              }}
            >
              {currentApple.text}
            </div>
          </foreignObject>

          {isHod && (
  <foreignObject
    x={isIPhone ? 45 : 56}
    y={isIPhone ? 315 : 319}
    width={isIPhone ? 280 : 260}
    height="105"
  >
    <div
      xmlns="http://www.w3.org/1999/xhtml"
      style={{
        position: "relative",
        width: "100%",
        height: "100%",
        boxSizing: "border-box",

        color: "white",
        textAlign: "center",
        direction: "rtl",
        textShadow: "0 1px 3px rgba(80, 0, 0, 0.5)",

        transform: isIPhone
          ? "translateX(-0.9rem)"
          : "none",

        WebkitTextSizeAdjust: "100%",
        textSizeAdjust: "100%",
      }}
    >
      <p
        className="text-hod"
        style={{
          width: "100%",
          margin: 0,
          padding: 0,
          fontSize: isIPhone ? "16px" : "17px",
          lineHeight: 1.2,
          textAlign: "center",
          direction: "rtl",
          
        }}
      >
        {currentApple.text2}
      </p>

      <p
        className="text-worm"
        style={{
          width: "100%",
          margin: "0.2rem 0 0",
          padding: 0,
          fontSize: isIPhone ? "14px" : "14px",
          lineHeight: 1.2,
          textAlign: "center",
          direction: "rtl",
        }}
      >
        {currentApple.textWorm}
      </p>

      <button
        type="button"
        className="hod-btn"
        onClick={() => setShowPopup(true)}
        aria-label="פתיחת מידע על מגמות הו״ד"
        style={{
          position: "absolute",
          right: isIPhone ? "9rem" : "6rem",
          bottom: isIPhone ? "2rem" : "1rem",
          margin: 0,
          cursor: "pointer",
        }}
      >
        לחצו!
      </button>
    </div>
  </foreignObject>
)}
        </svg>
      </div>

      {showPopup && (
        <div className="overlay">
          <div className="popup">
            <p className="popup-hod-text1">תחת קורס הו״ד יש 6 מגמות</p>
            <p className="popup-hod-microcopy">
              לחצו על המגמות לעוד מידע!
            </p>

            <Worm onCompleteChange={setWormDone} />

            <button
              className="close-goal-btn"
              disabled={!wormDone}
              style={{
                opacity: wormDone ? 1 : 0.4,
                pointerEvents: wormDone ? "auto" : "none",
              }}
              onClick={() => setShowPopup(false)}
            >
              סגור
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default Apple;
